// // This SR latch will set Q to 0 and Qn to 1 when S is high and R is low
module SR_latch (  
    input wire S,  
    input wire R,  
    output reg Q,  
    output reg Qn  
);  
    always @(S or R) begin  
        if (S && !R) begin  
            Q <= 1;  
            Qn <= 0;  
        end else if (!S && R) begin  
            Q <= 0;  
            Qn <= 1;  
        end  
    end   
endmodule
